// do {
//   console.log(i);
//   // i++ yoxdur, dövr sonsuzdur
// } while (i < 5);
// Düzgün yol
let i = 0;
do {
  console.log(i);
  i++;
} while (i < 5);
// Çıxış:
// 0
// 1
// 2
// 3
// 4

