content.text:
The syntax of a `do...while` loop is:
```javascript
do {
  // code to execute
} while (condition);
```
- **Code Block**: Executes at least once.
- **Condition**: Checked after each iteration. If `true`, the loop continues; if `false`, it stops.

content.code:
// Basic do...while loop example
let i = 0;
do {
  console.log(i);
  i++;
} while (i < 5);
// Output:
// 0
// 1
// 2
// 3
// 4

// do...while loop with an array
const fruits = ['apple', 'pear', 'orange'];
let i = 0;
do {
  console.log(fruits[i]);
  i++;
} while (i < fruits.length);
// Output:
// apple
// pear
// orange

// break and continue example
let i = 0;
do {
  if (i === 3) {
    break; // stops the loop
  }
  console.log(i);
  i++;
} while (i < 5);
// Output:
// 0
// 1
// 2

i = 0;
do {
  i++;
  if (i === 3) {
    continue; // skips 3
  }
  console.log(i);
} while (i < 5);
// Output:
// 1
// 2
// 4
// 5

// Guaranteed one execution example
let i = 5;
do {
  console.log(i);
  i++;
} while (i < 5);
// Output:
// 5

// Error-prone example
// Error: Infinite loop
// let i = 0;
// do {
//   console.log(i);
//   // i++ is missing, causing an infinite loop
// } while (i < 5);
// Correct approach
let i = 0;
do {
  console.log(i);
  i++;
} while (i < 5);
// Output:
// 0
// 1
// 2
// 3
// 4

