content.text:
Синтаксис цикла `do...while` следующий:
```javascript
do {
  // код для выполнения
} while (условие);
```
- **Блок кода**: Выполняется хотя бы один раз.
- **Условие**: Проверяется после каждой итерации. Если `true`, цикл продолжается; если `false`, он останавливается.

content.code:
// Пример базового цикла do...while
let i = 0;
do {
  console.log(i);
  i++;
} while (i < 5);
// Вывод:
// 0
// 1
// 2
// 3
// 4

// Цикл do...while с массивом
const fruits = ['яблоко', 'груша', 'апельсин'];
let i = 0;
do {
  console.log(fruits[i]);
  i++;
} while (i < fruits.length);
// Вывод:
// яблоко
// груша
// апельсин

// Пример break и continue
let i = 0;
do {
  if (i === 3) {
    break; // останавливает цикл
  }
  console.log(i);
  i++;
} while (i < 5);
// Вывод:
// 0
// 1
// 2

i = 0;
do {
  i++;
  if (i === 3) {
    continue; // пропускает 3
  }
  console.log(i);
} while (i < 5);
// Вывод:
// 1
// 2
// 4
// 5

// Пример гарантированного одного выполнения
let i = 5;
do {
  console.log(i);
  i++;
} while (i < 5);
// Вывод:
// 5

// Пример с ошибкой
// Ошибка: Бесконечный цикл
// let i = 0;
// do {
//   console.log(i);
//   // i++ отсутствует, вызывая бесконечный цикл
// } while (i < 5);
// Правильный подход
let i = 0;
do {
  console.log(i);
  i++;
} while (i < 5);
// Вывод:
// 0
// 1
// 2
// 3
// 4

